import sys
from pathlib import Path

def generate_manifest(filenames: list[str]) -> list[dict]:
    manifest = []
    seen_targets = {}
    for name in filenames:
        new_name = name.lower().replace(" ", "-").replace("_", "-")
        entry = {"old": name, "new": new_name, "conflict": False}
        if new_name in seen_targets:
            entry["conflict"] = True
            seen_targets[new_name]["conflict"] = True
        seen_targets[new_name] = entry
        manifest.append(entry)
    return manifest

def show_diff(manifest):
    for e in manifest:
        status = "[CONFLICT]" if e["conflict"] else ""
        print(f"\033[31m{e['old']}\033[0m -> \033[32m{e['new']}\033[0m {status}")

def execute(manifest):
    confirm = input("Execute renames? [yes/no]: ")
    if confirm.lower() != "yes":
        print("Aborted. No files renamed."); sys.exit(0)
    for e in manifest:
        if not e["conflict"]:
            Path(e["old"]).rename(e["new"])
